<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Expense Tracker</title>
    <style>
        body {
            font-family: sans-serif;
            line-height: 1.5;
            max-width: 600px;
            margin: 20px auto;
            padding: 0 15px;
            color: #333;
        }
        h1, h2 { color: #222; }
        .card {
            border: 1px solid #ddd;
            padding: 20px;
            border-radius: 8px;
            margin-bottom: 20px;
            background: #f9f9f9;
        }
        .form-group { margin-bottom: 15px; }
        label { display: block; font-weight: bold; margin-bottom: 5px; }
        input, select, textarea {
            width: 100%;
            padding: 8px;
            box-sizing: border-box;
            border: 1px solid #ccc;
            border-radius: 4px;
        }
        button {
            cursor: pointer;
            padding: 10px 15px;
            border: none;
            border-radius: 4px;
            background: #007bff;
            color: white;
            font-weight: bold;
        }
        button:hover { background: #0056b3; }
        #form-error {
            color: #d9534f;
            margin-bottom: 15px;
            font-weight: bold;
            min-height: 1.2em;
        }
        .filters {
            display: grid;
            grid-template-columns: 1fr 1fr 1fr;
            gap: 10px;
            margin-bottom: 20px;
        }
        .summary-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
            gap: 10px;
            margin-top: 10px;
        }
        .cat-box {
            background: #eee;
            padding: 10px;
            border-radius: 4px;
            text-align: center;
            font-size: 0.9em;
        }
        #total-display {
            font-size: 1.5em;
            font-weight: bold;
            margin-bottom: 10px;
        }
        .expense-list { margin-top: 20px; }
        .expense {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 10px;
            border-bottom: 1px solid #eee;
            background: white;
        }
        .exp-info { flex-grow: 1; }
        .exp-date { font-size: 0.85em; color: #666; }
        .exp-cat { 
            display: inline-block;
            background: #e2e2e2;
            padding: 2px 6px;
            border-radius: 4px;
            font-size: 0.75em;
            margin-left: 8px;
            text-transform: capitalize;
        }
        .exp-amount { font-weight: bold; margin-right: 15px; }
        .exp-del {
            background: #ff4d4d;
            padding: 5px 10px;
            font-size: 0.8em;
        }
        .exp-del:hover { background: #cc0000; }
    </style>
</head>
<body>

    <h1>Expense Tracker</h1>

    <!-- Entry Form -->
    <div class="card">
        <h2>Add Expense</h2>
        <div id="form-error"></div>
        <form id="expense-form">
            <div class="form-group">
                <label for="amount">Amount</label>
                <input type="number" id="amount" step="0.01" placeholder="0.00">
            </div>
            <div class="form-group">
                <label for="category">Category</label>
                <select id="category">
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>
            <div class="form-group">
                <label for="date">Date</label>
                <input type="date" id="date">
            </div>
            <div class="form-group">
                <label for="note">Note (Optional)</label>
                <textarea id="note" rows="2"></textarea>
            </div>
            <button type="submit" id="add-expense">Add Expense</button>
        </form>
    </div>

    <!-- Filters -->
    <div class="card">
        <h2>Filters</h2>
        <div class="filters">
            <div>
                <label for="filter-category">Category</label>
                <select id="filter-category">
                    <option value="all">All</option>
                    <option value="groceries">Grokeys</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>
            <div>
                <label for="filter-from">From</label>
                <input type="date" id="filter-from">
            </div>
            <div>
                <label for="filter-to">To</label>
                <input type="date" id="filter-to">
            </div>
        </div>

        <!-- Summary -->
        <div id="total-display">Total: <span id="total">0.00</span></div>
        <div class="summary-grid">
            <div class="cat-box"><span class="cat-total" data-cat="groceries">Groceries: 0.00</span></div>
            <div class="cat-box"><span class="cat-total" data-cat="transport">Transport: 0.00</span></div>
            <div class="cat-box"><span class="cat-total" data-cat="bills">Bills: 0.00</span></div>
            <div class="cat-box"><span class="cat-total" data-cat="fun">Fun: 0.00</span></div>
        </div>
    </div>

    <!-- List -->
    <div id="expense-list" class="expense-list">
        <!-- Rows injected here -->
    </div>

    <script>
        // State Management
        let expenses = JSON.parse(localStorage.getItem('expenses')) || [];

        const form = document.getElementById('expense-filter-form'); // Not used, using ID below
        const expenseForm = document.getElementById('expense-form');
        const amountInput = document.getElementById('amount');
        const categoryInput = document.getElementById('category');
        const dateInput = document.getElementById('date');
        const noteInput = document.getElementById('note');
        const errorDiv = document.getElementById('form-error');

        const filterCat = document.getElementById('filter-category');
        const filterFrom = document.getElementById('filter-from');
        const filterTo = document.getElementById('filter-to');

        const totalEl = document.getElementById('total');
        const listContainer = document.getElementById('expense-list');

        // Persistence
        function save() {
            localStorage.setItem('expenses', JSON.stringify(expenses));
        }

        // Core Logic: Render
        function render() {
            const catFilter = filterCat.value;
            const fromDate = filterFrom.value;
            const toDate = filterTo.value;

            // Filter logic
            const filtered = expenses.filter(exp => {
                const matchCat = (catFilter === 'all' || exp.category === catFilter);
                const matchFrom = (!fromDate || exp.date >= fromDate);
                const matchTo = (!toDate || exp.date <= toDate);
                return matchCat && matchFrom && matchTo;
            });

            // Sort: Newest first (by date)
            filtered.sort((a, b) => new Date(b.date) - new Date(a.date));

            // Clear UI
            listContainer.innerHTML = '';

            // Calculate Totals
            let grandTotal = 0;
            const catTotals = { groceries: 0, transport: 0, bills: 0, fun: 0 };

            filtered.forEach(exp => {
                grandTotal += exp.amount;
                if (catTotals.hasOwnProperty(exp.category)) {
                    catTotals[exp.pre_calc_cat || exp.category] += exp.amount; // fallback logic safety
                }
                // Re-calculating correctly for the specific categories
                catTotals[exp.category] += exp.amount;

                const row = document.createElement('div');
                row.className = 'expense';
                row.innerHTML = `
                    <div class="exp-info">
                        <div><strong>${exp.amount.toFixed(2)}</strong> <span class="exp-cat">${exp.category}</span></div>
                        <div class="exp-date">${exp.date} ${exp.note ? ' - ' + exp.note : ''}</div>
                    </div>
                    <button class="exp-del" data-id="${exp.id}">Delete</button>
                `;
                listContainer.appendChild(row);
            });

            // Update Summary UI
            totalEl.textContent = grandTotal.toFixed(2);
            document.querySelectorAll('.cat-total').forEach(el => {
                const cat = el.getAttribute('data-cat');
                const val = catTotals[cat] || 0;
                // Requirement: "text contains that category's visible total"
                // We will format it as "Category: 0.00"
                const label = cat.charAt(0).toUpperCase() + cat.slice(1);
                el.textContent = `${label}: ${val.toFixed(2)}`;
            });

            // Re-attach delete listeners (or use delegation)
        }

        // Event Delegation for Delete
        listContainer.addEventListener('click', (e) => {
            if (e.target.classList.undetermined || e.target.classList.contains('exp-del')) {
                const id = parseFloat(e.target.getAttribute('data-id')); // Using ID as number or string
                // Since we use unique IDs, let's find by a more robust way if needed, 
                // but for this simple app, finding index via a property is fine.
                // Let's refine: Use Date.now() as ID.
                const targetId = e.target.getAttribute('data-id');
                expenses = expenses.filter(exp => exp.id != targetId);
                save();
                render();
            }
        });

        // Form Submission
        expenseForm.addEventListener('submit', (e) => {
            e.preventDefault();
            errorDiv.textContent = '';

            const amount = parseFloat(amountInput.value);
            const category = categoryInput.value;
            const date = dateInput.value;
            const note = noteInput.value.trim();

            // Validation
            if (isNaN(amount) || amount <= 0) {
                errorDiv.textContent = "Please enter a valid positive amount.";
                return;
            }
            if (!date) {
                errorDiv.textContent = "Please select a date.";
                return;
            }

            // Add Expense
            const newExp = {
                id: Date.now(),
                amount,
                category,
                date,
                note
            };

            expenses.push(newExp);
            save();
            render();

            // Reset Form
            amountInput.value = '';
            dateInput.value = '';
            noteInput.value = '';
            categoryInput.selectedIndex = 0;
        });

        // Filter Listeners
        filterCat.addEventListener('change', render);
        filterFrom.addEventListener('change', render);
        filterTo.addEventListener('change', render);

        // Initial Load
        render();
    </script>
</body>
</html>
